function [u,covar,cntRat,fitImg,fitX,fitY] = fFitGaus2DV02(x,y,img,rat)% Perform fitting to 2d Gaussian distribution%% [u,covar,t,iter,fitImg,fitX,fitY] = fFitGausV01(x,cnts,ratio)% x: axis information (x axis)% y: counts for each point (yaxis)% img: source image% rat: difine threshold to fit, 0.2 will cut below 0.2 x peak%% u: fitted mean for each gaussian (each mean is a 2x1 vector)% covar: fitted covariance for each gaussian. this is a 2x2xM matrix.% peak: peak from fit result  % fitImg: image used for fitting% fitX,fitY: axes for fitting%  %%%%%%%%%%%%%%%%%%%%%%%%%%%%% Fit Gaussian 2D, ver.2%% Kei Nakamura% Created on Friday, February 12th 2010.% Modified on %% ver.1: created% ver.2: obtain peak value%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body% preform ROi with threshold defined by "rat"[szy,szx] = size(img);[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:szx],sum(img),rat);    % for roix1 = round(peak-wLOut); x2 = round(peak+wHOut);[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:szy],sum(img,2),rat);    % for roiy1 = round(peak-wLOut); y2 = round(peak+wHOut);fitImg = img(y1:y2,x1:x2);   % image for 2D-fittingfitX = x(x1:x2); fitY = y(y1:y2);   % axis for fitting% making array for fitting functionhst = fGetHst2DV01(fitX,fitY,fitImg);[u,covar,t,iter] = fit_mix_2D_gaussian(hst,1)% to get peak value[mshX,mshY] = meshgrid(x,y);  % meshxF = (mshX-u(1)).^2/covar(1,1);     % x termyF = (mshY-u(2)).^2/covar(2,2);     % y termcrF = covar(1,2)/(covar(1,1)*covar(2,2))^0.5;   % correlation factorxyF = -2*crF*(mshX-u(1)).*(mshY-u(2))/(covar(1,1)*covar(2,2))^0.5;  % xy termcf = -0.5/(1-crF^2);    % coefficientfitMat = exp(cf*(xF+yF+xyF));   % fitting result image% comparison% fitTtlCnt = sum(sum(fitMat))% fitPrtCnt = sum(sum(fitMat(y1:y2,x1:x2)))% prtCnt = sum(sum(img(y1:y2,x1:x2)))% % nrm = 2*pi*sqrt(covar(1,1)*covar(2,2)*(1-crF))% peak = (x(2)-x(1))*(y(2)-y(1))*fitTtlCnt/nrmcoeff = sum(sum(img(y1:y2,x1:x2)))/sum(sum(fitMat(y1:y2,x1:x2)));fitMat = coeff*fitMat;cntRat = sum(sum(fitMat))/sum(sum(img));    % count ratio% figure(7)% subplot(1,3,1)% pcolor(x,y,img)% shading interp% colorbar% subplot(1,3,2)% pcolor(x,y,fitMat)% shading interp% colorbar% subplot(1,3,3)% pcolor(x,y,img-fitMat)% shading interp% colorbar
